from board import Board, PieceType

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = PieceType.RED

    def print_board(self):
        self.board.print()

    def get_move(self):
        move = input(f"Player {PieceType(self.current_player).name}, enter your move (from-to): ")
        return move

    def is_valid_move(self, move):
        return self.board.is_valid_move(move, self.current_player)

    def make_move(self, move):
        if self.is_valid_move(move):
            self.board.make_move(move, self.current_player)
            self.current_player = PieceType(3 - self.current_player.value)  # Switch players

    def check_game_over(self):
        return self.board.check_win() or self.board.check_draw()

    def start(self):
        while not self.check_game_over():
            self.print_board()
            move = self.get_move()
            self.make_move(move)
        if self.board.check_win():
            print(f"Player {PieceType(self.current_player).name} wins!")
        else:
            print("Game is a draw!")

if __name__ == "__main__":
    game = CheckersGame()
    game.start()
```

