from piece import Piece, PieceType

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(PieceType.RED)
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(PieceType.BLACK)

    def print(self):
        for row in self.board:
            for piece in row:
                if piece:
                    print(piece.symbol, end=" ")
                else:
                    print(" .", end=" ")
            print()

    def is_valid_move(self, move, player):
        from_pos, to_pos = move.split('-')
        from_x, from_y = int(from_pos[0]), int(from_pos[1])
        to_x, to_y = int(to_pos[0]), int(to_pos[1])

        if (from_x, from_y) == (to_x, to_y):
            return False

        if self.board[from_x][from_y] and self.board[from_x][from_y].player_type == player:
            if abs(from_x - to_x) in [1, 2] and abs(from_y - to_y) == 1:
                if self.board[to_x][to_y]:
                    return False
                if (abs(from_x - to_x) == 2) and not self.board[(from_x + to_x) // 2][(from_y + to_y) // 2]:
                    return False
                return True

        return False

    def make_move(self, move, player):
        from_pos, to_pos = move.split('-')
        from_x, from_y = int(from_pos[0]), int(from_pos[1])
        to_x, to_y = int(to_pos[0]), int(to_pos[1])

        if self.is_valid_move(move, player):
            self.board[to_x][to_y] = Piece(player)
            self.board[from_x][from_y] = None

    def check_win(self):
        red_count = sum(1 for row in range(8) for piece in range(8) if self.board[row][piece] and self.board[row][piece].player_type == PieceType.RED)
        black_count = sum(1 for row in range(8) for piece in range(8) if self.board[row][piece] and self.board[row][piece].player_type == PieceType.BLACK)

        return red_count == 0 or black_count == 0

    def check_draw(self):
        # Placeholder for draw detection logic
        return False
```

